module dram_cell(  
    input wire clk,  
    input wire wr_en,  
    input wire [15:0] data_in,  
    output reg [15:0] data_out  
);  
    reg [15:0] cell_data;  

    always @(posedge clk) begin  
        if (wr_en) begin  
            cell_data <= data_in;  
        end  
        data_out <= cell_data;  
    end  
endmodule
